import { z } from 'zod';
import * as S from './schemas';
import { request, jsonBody } from './fetcher';

export { ApiError } from './fetcher';

// Workspaces -----------------------------------------------------------------
export const listWorkspaces = (q: URLSearchParams = new URLSearchParams()) =>
  request(z.array(S.workspaceSummary), `/workspaces?${q.toString()}`);

export const getWorkspace = (
  model: string,
  session: string,
  opts: { validate?: boolean; include_raw?: boolean } = {},
) => {
  const qs = new URLSearchParams();
  if (opts.validate) qs.set('validate', 'true');
  if (opts.include_raw) qs.set('include_raw', 'true');
  return request(
    S.workspaceDetail,
    `/workspaces/${encodeURIComponent(model)}/${encodeURIComponent(session)}?${qs.toString()}`,
  );
};

export const createWorkspace = (data: {
  model_name: string;
  session_id: string;
  label?: string | null;
  description?: string | null;
  task_tag?: string | null;
  block_size?: number | null;
}) => request(S.workspaceDetail, '/workspaces', jsonBody(data));

export const updateMetadata = (
  model: string,
  session: string,
  data: { label?: string | null; description?: string | null; task_tag?: string | null },
) =>
  request(
    S.workspaceDetail,
    `/workspaces/${encodeURIComponent(model)}/${encodeURIComponent(session)}/metadata`,
    { method: 'PUT', body: JSON.stringify(data) },
  );

export const forkWorkspace = (
  model: string,
  session: string,
  data: {
    dst_session_id: string;
    branch_reason: string;
    at_turn?: string | null;
    dst_model_name?: string | null;
    label?: string | null;
    description?: string | null;
    task_tag?: string | null;
  },
) =>
  request(
    S.workspaceDetail,
    `/workspaces/${encodeURIComponent(model)}/${encodeURIComponent(session)}/fork`,
    jsonBody(data),
  );

export const setPinned = (model: string, session: string, pinned: boolean) =>
  request(
    S.workspaceDetail,
    `/workspaces/${encodeURIComponent(model)}/${encodeURIComponent(session)}/pin`,
    pinned ? jsonBody({ pinned: true }) : { method: 'DELETE' },
  );

export const validateWorkspace = (model: string, session: string) =>
  request(
    S.validationResult,
    `/workspaces/${encodeURIComponent(model)}/${encodeURIComponent(session)}/validate`,
    jsonBody({}),
  );

// Lineage + diff -------------------------------------------------------------
export const getLineage = (model: string, session: string) =>
  request(
    S.lineageResponse,
    `/workspaces/${encodeURIComponent(model)}/${encodeURIComponent(session)}/lineage`,
  );

export const diff = (
  left_model: string,
  left_session: string,
  right_model: string,
  right_session: string,
) => {
  const qs = new URLSearchParams({ left_model, left_session, right_model, right_session });
  return request(S.sessionDiff, `/diff?${qs.toString()}`);
};

// Transfers ------------------------------------------------------------------
export const exportBundle = (data: {
  model_name: string;
  session_id: string;
  out_filename?: string | null;
  allow_missing_blocks?: boolean;
}) =>
  request(
    z.object({
      path: z.string(),
      block_count: z.number().int(),
      missing_block_count: z.number().int(),
      grade: z.string(),
    }),
    '/transfers/export',
    jsonBody(data),
  );

export const listBundles = () => request(z.array(S.bundleInfo), '/transfers/bundles');

export const inspectBundle = (bundle_filename: string) =>
  request(S.bundleInfo, '/transfers/inspect', jsonBody({ bundle_filename }));

export const importBundle = (data: {
  bundle_filename: string;
  conflict_policy: 'fail' | 'rename' | 'overwrite';
  re_root_lineage?: boolean;
  expected_model_name?: string | null;
  expected_block_size?: number | null;
}) =>
  request(
    z.object({
      model_name: z.string(),
      session_id: z.string(),
      manifest_path: z.string(),
      blocks_written: z.number().int(),
      blocks_skipped: z.number().int(),
      source_session_id: z.string(),
      conflict_policy: z.string(),
      re_rooted: z.boolean(),
      provenance: z.record(z.any()),
    }),
    '/transfers/import',
    jsonBody(data),
  );

export const pinBundle = (bundle_filename: string, pinned: boolean) =>
  request(
    z.object({ bundle_filename: z.string(), pinned: z.boolean() }),
    '/transfers/bundles/pin',
    jsonBody({ bundle_filename, pinned }),
  );

