export const envInfo = () => request(S.environmentInfo, '/env');
export const health = () => request(S.healthCheckResult, '/env/health', jsonBody({}));

// Models ---------------------------------------------------------------------
export const listCatalog = () => request(S.catalogResponse, '/models/catalog');
