// Thin client for the OpenAI-compatible endpoints exposed by omlx.server.
// Lives outside `/ui/api` because the chat/completions surface is served
// directly by the FastAPI root at `/v1/*`.

export interface ChatMessage {
  role: 'system' | 'user' | 'assistant';
  content: string;
}

export interface ChatCompletionChoiceDelta {
  content?: string;
  role?: string;
}

export class ChatError extends Error {
  constructor(public status: number, public detail: string) {
    super(`[${status}] ${detail}`);
  }
}

async function parseError(resp: Response): Promise<ChatError> {
  let detail = resp.statusText;
  try {
    const body = await resp.json();
    if (body && typeof body.error === 'object' && typeof body.error.message === 'string') {
      detail = body.error.message;
    } else if (body && typeof body.detail === 'string') {
      detail = body.detail;
    }
  } catch {
    /* ignore */
  }
  return new ChatError(resp.status, detail);
}

export async function listModels(): Promise<string[]> {
  const resp = await fetch('/v1/models');
  if (!resp.ok) throw await parseError(resp);
  const body = (await resp.json()) as { data?: Array<{ id: string }> };
  return (body.data ?? [])
    .map((m) => m.id)
    .filter((id) => typeof id === 'string' && id.length > 0);
}

export interface ChatCompletionRequest {
  model: string;
  messages: ChatMessage[];
  temperature?: number;
  max_tokens?: number;
  stream?: boolean;
}

export async function chatCompletion(
  req: ChatCompletionRequest,
  signal?: AbortSignal,
): Promise<string> {
  const resp = await fetch('/v1/chat/completions', {
    method: 'POST',
    headers: { 'content-type': 'application/json' },
    body: JSON.stringify({ ...req, stream: false }),
    signal,
  });
  if (!resp.ok) throw await parseError(resp);
  const body = (await resp.json()) as {
    choices?: Array<{ message?: { content?: string } }>;
  };
  return body.choices?.[0]?.message?.content ?? '';
}

// Streams tokens from `/v1/chat/completions` via SSE. Yields the cumulative
// assistant text after each chunk. Terminates when the server emits
// `data: [DONE]` or the stream closes.
export async function* streamChatCompletion(
  req: ChatCompletionRequest,
  signal?: AbortSignal,
): AsyncGenerator<string, void, void> {
  const resp = await fetch('/v1/chat/completions', {
    method: 'POST',
    headers: { 'content-type': 'application/json' },
    body: JSON.stringify({ ...req, stream: true }),
    signal,
  });
  if (!resp.ok) throw await parseError(resp);
  if (!resp.body) throw new ChatError(500, 'no response body from /v1/chat/completions');

  const reader = resp.body.getReader();
  const decoder = new TextDecoder('utf-8');
  let buffer = '';
  let acc = '';

  while (true) {
    const { value, done } = await reader.read();
    if (done) break;
    buffer += decoder.decode(value, { stream: true });

    let sep: number;
    while ((sep = buffer.indexOf('\n\n')) !== -1) {
      const raw = buffer.slice(0, sep);
      buffer = buffer.slice(sep + 2);
      for (const line of raw.split('\n')) {
        if (!line.startsWith('data:')) continue;
        const payload = line.slice(5).trim();
        if (!payload) continue;
        if (payload === '[DONE]') return;
        try {
          const evt = JSON.parse(payload) as {
            choices?: Array<{ delta?: ChatCompletionChoiceDelta }>;
          };
          const delta = evt.choices?.[0]?.delta?.content;
          if (typeof delta === 'string' && delta.length > 0) {
            acc += delta;
            yield acc;
          }
        } catch {
          /* ignore malformed SSE frame */
        }
      }
    }
  }
}
