// Centralized query-key factory. Use `qk.*` everywhere so cache keys can't drift.
export const qk = {
  workspaces: (params?: string) =>
    params ? (['workspaces', params] as const) : (['workspaces'] as const),
  workspace: (model: string, session: string) =>
    ['workspace', model, session] as const,
  lineage: (model: string, session: string) =>
    ['workspace', model, session, 'lineage'] as const,
  bundles: () => ['bundles'] as const,
  maintenanceStats: () => ['maintenance', 'stats'] as const,
  env: () => ['env'] as const,
  modelsCatalog: () => ['models', 'catalog'] as const,
  modelsInstalled: () => ['models', 'installed'] as const,
  modelsTasks: () => ['models', 'tasks'] as const,
} as const;
