// Zod mirrors of the Pydantic DTOs in omlx/ui_api/schemas.py.
// Keep these in lockstep with that file — any backend change needs a
// matching schema change here.
import { z } from 'zod';

export const modelCompat = z.object({
  model_name: z.string(),
  block_size: z.number().int().nullable().optional(),
  schema: z.string().default('2'),
});

export const turnInfo = z.object({
  turn_id: z.string(),
  committed_at: z.number(),
  block_count: z.number().int(),
  note: z.string().nullable().optional(),
  branch_reason: z.string().nullable().optional(),
});

export const lineageInfo = z.object({
  session_id: z.string(),
  label: z.string().nullable().optional(),
  description: z.string().nullable().optional(),
  created_at: z.number(),
  updated_at: z.number(),
  head_turn_id: z.string(),
  parent: z.tuple([z.string(), z.string()]).nullable().optional(),
  model_compat: modelCompat,
  turn_count: z.number().int(),
  task_tag: z.string().nullable().optional(),
});

export const replayReport = z.object({
  session_id: z.string(),
  model_name: z.string(),
  head_turn_id: z.string(),
  total_blocks: z.number().int(),
  present_blocks: z.number().int(),
  missing_blocks: z.array(z.string()),
  replayable: z.boolean(),
  grade: z.string(),
});

export const workspaceSummary = z.object({
  model_name: z.string(),
  session_id: z.string(),
  label: z.string().nullable().optional(),
  head_turn_id: z.string(),
  turn_count: z.number().int(),
  updated_at: z.number(),
  last_used_at: z.number().nullable().optional(),
  pinned: z.boolean(),
  integrity_grade: z.string(),
  branch_count: z.number().int(),
  has_parent: z.boolean(),
  exportable: z.boolean(),
  model_compat: modelCompat,
  task_tag: z.string().nullable().optional(),
});

export const workspaceDetail = z.object({
  model_name: z.string(),
  session_id: z.string(),
  lineage: lineageInfo,
  turns: z.array(turnInfo),
  pinned: z.boolean(),
  last_used_at: z.number().nullable().optional(),
  integrity_grade: z.string(),
  exportable: z.boolean(),
  replay: replayReport.nullable().optional(),
  branch_reason: z.string().nullable().optional(),
  children_count: z.number().int(),
  raw: z.record(z.any()).nullable().optional(),
});

export const lineageNode = z.object({
  model_name: z.string(),
  session_id: z.string(),
  head_turn_id: z.string(),
  label: z.string().nullable().optional(),
  integrity_grade: z.string(),
  branch_reason: z.string().nullable().optional(),
  pinned: z.boolean(),
  parent: z.tuple([z.string(), z.string()]).nullable().optional(),
  depth: z.number().int(),
  role: z.enum(['self', 'ancestor', 'descendant', 'dangling']),
});

export const lineageResponse = z.object({
  focus: z.tuple([z.string(), z.string()]),
  ancestors: z.array(lineageNode),
  descendants: z.array(lineageNode),
  dangling_parent: z.tuple([z.string(), z.string()]).nullable().optional(),
});

export const turnDiff = z.object({
  turn_id_a: z.string().nullable(),
  turn_id_b: z.string().nullable(),
  block_count_a: z.number().int(),
  block_count_b: z.number().int(),
  common_prefix_blocks: z.number().int(),
  diverged: z.boolean(),
});

export const sessionDiff = z.object({
  session_a: z.tuple([z.string(), z.string()]),
  session_b: z.tuple([z.string(), z.string()]),
  common_ancestor: z.tuple([z.string(), z.string()]).nullable().optional(),
  turn_count_a: z.number().int(),
  turn_count_b: z.number().int(),
  shared_turn_count: z.number().int(),
  per_turn: z.array(turnDiff),
});

export const validationResult = z.object({
  model_name: z.string(),
  session_id: z.string(),
  integrity_grade: z.string(),
  replay: replayReport,
  manifest_schema_version: z.string(),
  schema_ok: z.boolean(),
  exportable: z.boolean(),
  reported_at: z.number(),
});

export const bundleInfo = z.object({
  path: z.string(),
  size_bytes: z.number().int(),
  mtime: z.number(),
  pinned: z.boolean(),
  envelope: z.record(z.any()).nullable().optional(),
  manifest: z.record(z.any()).nullable().optional(),
});

export const pruneCandidate = z.object({
  kind: z.enum(['workspace', 'bundle']),
  reason: z.string(),
  action: z.enum(['eligible', 'protected']),
  model_name: z.string(),
  session_id: z.string(),
  path: z.string(),
  age_seconds: z.number(),
  last_used_at: z.number().nullable().optional(),
  integrity_grade: z.string().nullable().optional(),
  pinned: z.boolean(),
  prune_class: z.string().nullable().optional(),
});

export const prunePlan = z.object({
  model_name: z.string().nullable().optional(),
  now: z.number(),
  include_pinned: z.boolean(),
  requested_classes: z.array(z.string()),
  candidates: z.array(pruneCandidate),
  by_reason: z.record(z.array(pruneCandidate)),
  plan_signature: z.string(),
});

export const pruneReport = z.object({
  model_name: z.string().nullable().optional(),
  dry_run: z.boolean(),
  considered: z.number().int(),
  deleted: z.array(z.string()),
  errors: z.array(z.tuple([z.string(), z.string()])),
});

export const maintenanceStats = z.object({
  counters: z.record(z.number().int()),
  archive_root: z.string(),
  total_workspaces: z.number().int(),
  total_bytes: z.number().int(),
  total_bundles: z.number().int(),
});

export const environmentInfo = z.object({
  omlx_version: z.string(),
  python_version: z.string(),
  platform: z.record(z.string()),
  manifest_schema_version: z.string(),
  supported_manifest_versions: z.array(z.string()),
  bundle_version: z.string(),
  cache_layout: z.string(),
  archive_root: z.string(),
  ssd_cache_dir: z.string(),
  base_path: z.string(),
  bundle_export_dir: z.string(),
  bundle_import_dir: z.string(),
  mlx_lm_pinned: z.string().nullable().optional(),
});

export const healthCheckResult = z.object({
  ok: z.boolean(),
  checks: z.record(z.object({ ok: z.boolean(), detail: z.string() })),
  reported_at: z.number(),
});

// Models (UI catalog + HF downloads) ---------------------------------------
export const catalogModel = z.object({
  id: z.string(),
  repo_id: z.string(),
  display_name: z.string(),
  family: z.string(),
  size_label: z.string(),
  params: z.string(),
  quantization: z.string(),
  description: z.string(),
  tags: z.array(z.string()).default([]),
});

export const catalogResponse = z.object({
  models: z.array(catalogModel),
});

export const installedModel = z.object({
  id: z.string().nullable().optional(),
  model_path: z.string().default(''),
  loaded: z.boolean().default(false),
  is_loading: z.boolean().default(false),
  estimated_size: z.number().int().default(0),
  model_type: z.string().default('llm'),
  pinned: z.boolean().default(false),
});

export const installedResponse = z.object({
  models: z.array(installedModel),
});

export const downloadTask = z.object({
  task_id: z.string(),
  repo_id: z.string(),
  status: z.enum(['pending', 'downloading', 'completed', 'failed', 'cancelled']),
  progress: z.number().default(0),
  total_size: z.number().default(0),
  downloaded_size: z.number().default(0),
  error: z.string().nullable().optional(),
  created_at: z.number().nullable().optional(),
  started_at: z.number().nullable().optional(),
  completed_at: z.number().nullable().optional(),
  retry_count: z.number().int().default(0),
});

export const tasksResponse = z.object({
  tasks: z.array(downloadTask),
});

export const startDownloadResponse = z.object({
  task: downloadTask,
});

export type WorkspaceSummary = z.infer<typeof workspaceSummary>;
export type WorkspaceDetail = z.infer<typeof workspaceDetail>;
export type LineageResponse = z.infer<typeof lineageResponse>;
export type SessionDiff = z.infer<typeof sessionDiff>;
export type CatalogModel = z.infer<typeof catalogModel>;
export type InstalledModel = z.infer<typeof installedModel>;
export type DownloadTask = z.infer<typeof downloadTask>;
export type ValidationResult = z.infer<typeof validationResult>;
export type BundleInfo = z.infer<typeof bundleInfo>;
export type PrunePlan = z.infer<typeof prunePlan>;
export type PruneReport = z.infer<typeof pruneReport>;
export type MaintenanceStats = z.infer<typeof maintenanceStats>;
export type EnvironmentInfo = z.infer<typeof environmentInfo>;
export type HealthCheckResult = z.infer<typeof healthCheckResult>;
